css:
* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body {
    font-family: Arial, sans-serif;
    font-size: 11pt;
    color: #333;
    line-height: 1.6;
    padding: 20px;
}

/* ─ Header ── */
.header-table {
    width: 100%;
    border-collapse: collapse;
    margin-bottom: 10px;
}
.header-logo-cell {
    width: 130px;
    vertical-align: middle;
    text-align: left;
}
.header-title-cell {
    vertical-align: middle;
    text-align: center;
}
.header-spacer-cell {
    width: 130px;
}
.logo {
    max-width: 120px;
    max-height: 60px;
}
.doc-title {
    color: #2c3e50;
    font-size: 22pt;
    font-weight: bold;
    margin-bottom: 4px;
}
.doc-id {
    font-size: 12pt;
    color: #555;
}

.separator {
    border: none;
    border-top: 3px solid #2c3e50;
    margin: 16px 0 20px 0;
}

/* ── Section Header ── */
.section-header {
    color: #2c3e50;
    font-size: 13pt;
    font-weight: bold;
    padding-bottom: 6px;
    margin-top: 24px;
    margin-bottom: 14px;
    border-bottom: 2px solid #2c3e50;
}

/* ── Info Grid (2-col via table) ── */
.grid-table {
    width: 100%;
    border-collapse: separate;
    border-spacing: 8px;
    margin-bottom: 10px;
}
.info-box {
    border: 1px solid #ddd;
    padding: 10px 12px;
    border-radius: 4px;
    background-color: #f9f9f9;
    vertical-align: top;
    width: 50%;
}
.info-box-full {
    border: 1px solid #ddd;
    padding: 10px 12px;
    border-radius: 4px;
    background-color: #f9f9f9;
    vertical-align: top;
}
.info-label {
    font-weight: bold;
    color: #2c3e50;
    font-size: 10pt;
    display: block;
    margin-bottom: 4px;
}
.info-value {
    color: #444;
    font-size: 11pt;
}

/* ── Text Content Block ── */
.text-block {
    border: 1px solid #ddd;
    padding: 14px;
    background-color: #f9f9f9;
    border-radius: 4px;
    margin-bottom: 16px;
    min-height: 60px;
    font-size: 11pt;
    color: #444;
    white-space: pre-wrap;
}

/* ── Approval Table ── */
.approval-table {
    width: 100%;
    border-collapse: collapse;
    margin-top: 12px;
    margin-bottom: 30px;
    font-size: 10pt;
}
.approval-table th {
    background-color: #34495e;
    color: #fff;
    padding: 9px 10px;
    text-align: left;
    border: 1px solid #2c3e50;
    font-size: 10pt;
}
.approval-table td {
    padding: 9px 10px;
    border: 1px solid #ddd;
}
.approval-table tr.even td {
    background-color: #f4f4f4;
}

/* ── Status Badge ── */
.status-badge {
    display: inline-block;
    padding: 3px 12px;
    border-radius: 12px;
    font-size: 10pt;
    font-weight: bold;
    background-color: #e8f4fd;
    color: #1a6fa0;
    border: 1px solid #aad4f0;
}

/* ── Footer ── */
.footer {
    margin-top: 50px;
    padding-top: 14px;
    border-top: 1px solid #ddd;
    text-align: left;
}
.footer-logo {
    max-width: 110px;
    max-height: 55px;
}

.print-format {
    padding: 0.75in 0.5in;
}

.row {
    margin-top: 5px !important;
}

.col {
  float: left;
  width: 50%;
  padding: 10px;
}

.row:after {
  content: "";
  display: table;
  clear: both;
}

td {
    font-size: 14px;
}

html:
{% set base_url = frappe.utils.get_url() %}{% set app_logo = frappe.db.get_single_value('Website Settings', 'app_logo') %}{% set company_name = frappe.db.get_default('Company') %}
<section>
        <div style="text-align: left;">
            {% if app_logo %}<img src="{{ base_url }}{{ app_logo }}" alt="Company Logo" height="100" style="height:100px;">{% else %}<strong>{{ company_name }}</strong>{% endif %}
        </div>
</section>


<div class="row">
  <div class="col">
      <table class="table table-borderless">
            <tbody>
              <tr>
                <td>Name:</td>
                <td>{{ doc.employee_name }}</td>
              </tr>
              <tr>
                <td>Department:</td>
                <td>{{ doc.department }} </td>
              </tr>
              <tr>
                <td>Date:</td>
                <td>{{ doc.posting_date }} </td>
              </tr>
              <tr>
                <td>KRA PIN:</td>
                <td>{{ doc.custom_kra_pin }} </td>
              </tr>
              <tr>
                <td>NHIF/SHIF:</td>
                <td>{{ doc.custom_nhif_number }} </td>
              </tr>
              <tr>
                <td>NSSF Number:</td>
                <td>{{ doc.custom_nssf_number }} </td>
              </tr>
              <tr>
                <td>ID Number:</td>
                <td>{{ doc.custom_id_number }} </td>
              </tr>
            </tbody>
            
          </table>
  </div>

</div>

<div class="">
<div class="row">
  <div class="col">
      <h2>Earnings</h2>
      <table class="table table-borderless">
        <thead>
          <tr>
            <th scope="col">Earnings:</th>
            <th scope="col">KES:</th>
          </tr>
        </thead>
        <tbody>
          {%- for row in doc.earnings -%}
              {%- if 'PAYE' not in row.get('salary_component', '') -%}
                  <tr>
                    <td>{{row.get('salary_component', 'Not Available')}}</td>
                    <td>{{frappe.format_value(row.get('amount', 0), { "fieldtype": "Currency" })}}</td>
                  </tr>
              {%- endif -%}
          {%- endfor -%}
        </tbody>
      </table>
  </div>

  <div class="col">
    <h2>PAYE Deductions</h2>
      <table class="table table-borderless">
        <tbody>
          {%- for row in doc.deductions -%}
              {%- set total = namespace(total_value=0) -%}
              {%- if 'PAYE' in row.get('salary_component', '') -%}
                  <tr>
                    <td>{{row.get('abbr', 'Not Available')}}% on first KSH</td>
                    <td>{{frappe.format_value(row.get('amount', 0), { "fieldtype": "Currency" })}}</td>
                  </tr>
              {%- endif -%}
          {%- endfor -%}
        </tbody>
      </table>
  </div>
</div>
</div>

<div class="row">
  <div class="col">
      <h2>Taxation</h2>
      <table class="table table-borderless">
          <tbody>
              {%- set ns = namespace(total_deductions=0) -%}
      
              {%- for row in doc.deductions -%}
                  {%- set amount = row.get('amount', 0) | float -%} {# Ensure amount is treated as a float #}
                  {%- if 'PAYE' in row.get('salary_component', '') -%}
                      {%- set ns.total_deductions = ns.total_deductions + amount -%}
                  {%- endif -%}
              {%- endfor -%}
      
              <tr>
                  <td>Tax Charged</td>
                  <td>{{ frappe.format_value(ns.total_deductions, { "fieldtype": "Currency" }) }}</td>
              </tr>
              
              {%- for row in doc.earnings -%}
                  {%- if 'Taxable' in row.get('salary_component', '') -%}
                      <tr>
                        <td>Taxable Pay</td>
                        <td>{{frappe.format_value(row.get('amount', 0), { "fieldtype": "Currency" })}}</td>
                      </tr>
                  {%- endif -%}
              {%- endfor -%}
              {%- set components_to_display = ['Benefit', 'Relief'] -%}

              {%- for component in components_to_display -%}
                  {%- set found = False -%}
                  
                  {%- for row in doc.deductions -%}
                      {%- if component in row.get('salary_component', '') -%}
                          {%- set found = True -%}
                          <tr>
                            <td>{{ row.get('salary_component', 'Not Available') }}</td>
                            <td>{{ frappe.format_value(row.get('amount', 0), { "fieldtype": "Currency" }) }}</td>
                          </tr>
                      {%- endif -%}
                  {%- endfor -%}
              {%- endfor -%}

          </tbody>
      </table>

  </div>
  <div class="col">
      <h2>Deductions</h2>
      <table class="table table-borderless">
          <tbody>
              {%- set ns = namespace(total_deductions=0) -%}
      
              {%- for row in doc.deductions -%}
                  {%- set amount = row.get('amount', 0) | float -%} {# Ensure amount is treated as a float #}
                  {%- if 'PAYE' in row.get('salary_component', '') or 'Relief' in row.get('salary_component', '') -%}
                      {%- set ns.total_deductions = ns.total_deductions + amount -%}
                  {%- endif -%}
              {%- endfor -%}
      
              <tr>
                  <td>PAYE</td>
                  <td>{{ frappe.format_value(ns.total_deductions, { "fieldtype": "Currency" }) }}</td>
              </tr>
              
              {%- set components_to_display = ['HL', 'NSSF1', 'NSSF2', 'IP'] -%}

              {%- for component in components_to_display -%}
                  {%- set found = False -%}
                  
                  {%- for row in doc.deductions -%}
                      {%- if component in row.get('abbr', '') -%}
                          {%- set found = True -%}
                          <tr>
                            <td>{{ row.get('salary_component', 'Not Available') }}</td>
                            <td>{{ frappe.format_value(row.get('amount', 0), { "fieldtype": "Currency" }) }}</td>
                          </tr>
                      {%- endif -%}
                  {%- endfor -%}
              {%- endfor -%}
              
              {%- set components_to_display = ['Hospital'] -%}

              {%- for component in components_to_display -%}
                  {%- set found = False -%}
                  
                  {%- for row in doc.deductions -%}
                      {%- if component in row.get('salary_component', '') -%}
                          {%- set found = True -%}
                          <tr>
                            <td>{{ row.get('salary_component', 'Not Available') }}</td>
                            <td>{{ frappe.format_value(row.get('amount', 0), { "fieldtype": "Currency" }) }}</td>
                          </tr>
                      {%- endif -%}
                  {%- endfor -%}
              {%- endfor -%}


          </tbody>
      </table>
  </div>
</div>

<table class="table table-borderless mt-5">
  <tbody>
      <tr>
          <td>Total Deduction</td>
          <td>{{frappe.format_value(doc.total_deduction, { "fieldtype": "Currency" })}}</td>
      </tr>
      <tr>
          <td>Net Pay</td>
          <td>{{frappe.format_value(doc.net_pay, { "fieldtype": "Currency" })}}</td>
      </tr>
  </tbody>
</table>

