		        filters={"parent": row.serial_and_batch_bundle}) %}
		    {% set serial_nos = [] %}
            {% set batches = {} %}

            {% if bundle_data %}
			    {% for data in bundle_data %}
			        {% if data.serial_no %}
			            {{ serial_nos.append(data.serial_no) or "" }}
			        {% endif %}

			        {% if data.batch_no %}
			            {{ batches.update({data.batch_no: data.qty}) or "" }}
			        {% endif %}
			    {% endfor %}
			{% endif %}

			<td style="width: 3%;">{{ row.idx }}</td>
			<td style="width: 20%;">
				{{ row.item_name }}
				{% if row.item_code != row.item_name -%}
				<br>Item Code: {{ row.item_code}}
				{%- endif %}
			</td>
			<td style="width: 10%; text-align: right;">{{ row.qty }} {{ row.uom or row.stock_uom }}</td>

			<td style="width: 30%; text-align: left;">{{ serial_nos|join(',') }}</td>
			<td style="width: 30%;">
			    {% if batches %}
                    {% for batch_no, qty in batches.items() %}
                        <p> {{batch_no}} : {{qty}} {{ row.uom or row.stock_uom }} </p>
                    {% endfor %}
                {% endif %}
			</td>

		</tr>
		{%- endfor -%}
	</tbody>
</table>
"}]

